using System;

class Program
{
    delegate string StringTransformer(string s);

    static void Main()
    {
        StringTransformer transform = ToUpper;
        transform += ToLower;
        transform += Reverse;

        string result = transform("Hello");  // Only last return value kept
        Console.WriteLine(result);

        // Using built-in delegates
        Func<string, string> upper = s => s.ToUpper();
        Console.WriteLine(upper("world"));
    }

    static string ToUpper(string s) => s.ToUpper();
    static string ToLower(string s) => s.ToLower();
    static string Reverse(string s) => new string(s.Reverse().ToArray());
}
